function composeAnswer(ctx: ComposeContext): string {
  switch (ctx.intent) {
    case "greeting":
      return composeGreetingAnswer();
    case "system-inventory":
      return "";
    case "planning-broad":
      return composePlanningBroadAnswer(ctx.query, ctx.facts);
    case "weather":
